using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public sealed class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public sealed class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public sealed class TicketRequest
{
    public required string Subject { get; set; }
    public required string Description { get; set; }
    public int Priority { get; set; } = 2;
}

public sealed class TicketClassificationResult
{
    public required string PredictedCategory { get; set; }
    public required Dictionary<string, float> Confidence { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public sealed class ModelTrainingService(ILogger<ModelTrainingService> logger)
{
    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public string TrainAndSaveModel(string dataPath, string modelPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(mlContext)
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        logger.LogInformation("Training model from {DataPath}...", dataPath);
        ITransformer model = pipeline.Fit(split.TrainSet);

        string metrics = Evaluate(mlContext, model, split.TestSet);

        Directory.CreateDirectory(Path.GetDirectoryName(modelPath)!);
        mlContext.Model.Save(model, data.Schema, modelPath);
        logger.LogInformation("Model saved to {ModelPath}", modelPath);

        return metrics;
    }

    private string Evaluate(MLContext mlContext, ITransformer model, IDataView testData)
    {
        IDataView predictions = model.Transform(testData);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, "Label");

        var report = $"""
            ===== Model Evaluation Metrics =====
            Macro Accuracy:    {metrics.MacroAccuracy:F4}
            Micro Accuracy:    {metrics.MicroAccuracy:F4}
            Log Loss:          {metrics.LogLoss:F4}
            Log Loss Reduction:{metrics.LogLossReduction:F4}

            Per-class metrics:
            {FormatPerClassMetrics(metrics)}
            ====================================
            """;

        logger.LogInformation("{Metrics}", report);
        return report;
    }

    private static string FormatPerClassMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        var lines = new List<string>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count && i < Categories.Length; i++)
        {
            lines.Add($"  {Categories[i],-12} LogLoss: {metrics.PerClassLogLoss[i]:F4}");
        }
        return string.Join(Environment.NewLine, lines);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController(
    PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
    ModelTrainingService trainingService) : ControllerBase
{
    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    [HttpPost("classify")]
    public ActionResult<TicketClassificationResult> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) || string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject and Description are required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
        {
            confidence[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpPost("train")]
    public ActionResult<string> Train()
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "model.zip");

        if (!System.IO.File.Exists(dataPath))
            return NotFound($"Training data not found at {dataPath}");

        string metrics = trainingService.TrainAndSaveModel(dataPath, modelPath);
        return Ok(metrics);
    }
}

